#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long d,x,w;
    bool operator<(const node&b)const
    {
        return x<b.x;
    }
}a[500010];
long long n,l,sum;
bool check(long long x)
{
    long long sum=0;
    long long l=1,r=n;
    for(long long i=1;i<=n;i++)
    {
        if(a[i].d>0&&a[i].x+x>=::l)
        {
            sum+=a[r--].w;
        }
        if(a[i].d<0&&a[i].x<=x)
        {
            sum+=a[l++].w;
        }
    }
    return sum*2>=(::sum);
}
int main()
{
    scanf("%lld%lld",&n,&l);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld%lld",&a[i].w,&a[i].x,&a[i].d);
        sum+=a[i].w;
    }
    sort(a+1,a+1+n);
    long long l=0,r=2e9,best;
    while(l<=r)
    {
        long long mid=(l+r)/2;
        if(check(mid))
        {
            best=mid;
            r=mid-1;
        }
        else
        {
            l=mid+1;
        }
    }
    vector<long long> v;
    long long ans=0;
    for(long long i=1;i<=n;i++)
    {
        if(a[i].d<0)
        {
            long long pos=lower_bound(v.begin(),v.end(),a[i].x-best*2)-v.begin();
            ans+=(int)(v.size())-pos;
        }
        else
        {
            v.push_back(a[i].x);
        }
    }
    printf("%lld",ans);
    return 0;
}
